import math

def solve(cities):
    n = len(cities)
    if n <= 3:
        return list(range(n))

    # Precompute distances
    def dist(i, j):
        dx = cities[i][0] - cities[j][0]
        dy = cities[i][1] - cities[j][1]
        return int(math.sqrt(dx*dx + dy*dy) + 0.5)

    # Build distance matrix for small n, else use function
    if n <= 150:
        D = [[0]*n for _ in range(n)]
        for i in range(n):
            for j in range(n):
                if i != j:
                    D[i][j] = dist(i, j)
        def d(i, j): return D[i][j]
    else:
        def d(i, j): return dist(i, j)

    # Candidate lists (nearest neighbors)
    K = min(10, n-1)
    candidates = []
    for i in range(n):
        dists = [(d(i, j), j) for j in range(n) if j != i]
        dists.sort()
        candidates.append([j for _, j in dists[:K]])

    # Nearest neighbor construction
    visited = [False] * n
    tour = [0]
    visited[0] = True
    for _ in range(n - 1):
        last = tour[-1]
        best_d = float('inf')
        best_j = -1
        for j in candidates[last]:
            if not visited[j]:
                dd = d(last, j)
                if dd < best_d:
                    best_d = dd
                    best_j = j
        if best_j == -1:
            for j in range(n):
                if not visited[j]:
                    dd = d(last, j)
                    if dd < best_d:
                        best_d = dd
                        best_j = j
        tour.append(best_j)
        visited[best_j] = True

    # Position array
    pos = [0] * n
    for i, c in enumerate(tour):
        pos[c] = i

    def tour_length():
        return sum(d(tour[i], tour[(i+1) % n]) for i in range(n))

    # 2-opt with candidate lists and don't-look bits
    def two_opt():
        improved = True
        dont_look = [False] * n
        while improved:
            improved = False
            for idx in range(n):
                if dont_look[idx]:
                    continue
                i = idx
                ci = tour[i]
                i1 = (i + 1) % n
                ci1 = tour[i1]
                found = False
                for cj in candidates[ci]:
                    j = pos[cj]
                    # Try edge (ci, ci1) with edge (cj, cj_next)
                    if d(ci, cj) >= d(ci, ci1):
                        break  # candidates sorted by distance
                    j1 = (j + 1) % n
                    cj1 = tour[j1]
                    if cj == ci or cj1 == ci:
                        continue
                    gain = d(ci, ci1) + d(cj, cj1) - d(ci, cj) - d(ci1, cj1)
                    if gain > 0:
                        # Reverse segment between i1 and j
                        # Make sure i1..j is the segment to reverse
                        if pos[cj] > pos[ci]:
                            left, right = i1, j
                        else:
                            left, right = j1, i
                        # Reverse tour[left..right]
                        l, r = left, right
                        while l < r:
                            tour[l], tour[r] = tour[r], tour[l]
                            pos[tour[l]] = l
                            pos[tour[r]] = r
                            l += 1
                            r -= 1
                        improved = True
                        found = True
                        dont_look[ci] = False
                        dont_look[ci1] = False
                        dont_look[cj] = False
                        dont_look[cj1] = False
                        # Update for next iteration
                        ci1 = tour[(pos[ci] + 1) % n]
                        i1 = pos[ci1]
                        break
                if not found:
                    dont_look[idx] = True

    # Or-opt: move segments of length seg_len
    def or_opt(seg_len):
        improved = True
        while improved:
            improved = False
            for i in range(n):
                # Segment: tour[i], tour[i+1], ..., tour[i+seg_len-1]
                seg = [tour[(i + k) % n] for k in range(seg_len)]
                prev_i = (i - 1) % n
                next_seg = (i + seg_len) % n

