                c_first = seg[0]
                c_last = seg[-1]
                c_next = tour[next_seg]

                if c_prev == c_next:
                    continue

                # Cost of removing segment
                remove_gain = d(c_prev, c_first) + d(c_last, c_next) - d(c_prev, c_next)

                # Try inserting after each candidate of c_first
                for cj in candidates[c_first]:
                    j = pos[cj]
                    # Skip positions within the segment
                    in_seg = False
                    for k in range(seg_len):
                        if (i + k) % n == j:
                            in_seg = True
                            break
                    if in_seg or j == prev_i:
                        continue

                    j1 = (j + 1) % n
                    cj1 = tour[j1]

                    if cj1 == c_first:
                        continue

                    insert_cost = d(cj, c_first) + d(c_last, cj1) - d(cj, cj1)

                    if remove_gain - insert_cost > 0:
                        # Perform the move
                        # Remove segment from tour
                        new_tour = []
                        idx = 0
                        orig = list(tour)
                        # Build without segment
                        seg_indices = set((i + k) % n for k in range(seg_len))
                        temp = [orig[k] for k in range(n) if k not in seg_indices]
                        # Find position of cj in temp
