                                tour[k] = new_tour[k]
                                pos[new_tour[k]] = k
                            improved = True
                            break

    # Also try reverse insertion for or-opt
    def or_opt_with_reverse(seg_len):
        improved = True
        while improved:
            improved = False
            for i in range(n):
                seg = [tour[(i + k) % n] for k in range(seg_len)]
                prev_i = (i - 1) % n
