                for cj in candidates[c_first] + candidates[c_last]:
                    j = pos[cj]
                    in_seg = False
                    for k in range(seg_len):
                        if (i + k) % n == j:
                            in_seg = True
                            break
                    if in_seg or j == prev_i:
                        continue

                    j1 = (j + 1) % n
                    cj1 = tour[j1]

                    # Forward insertion
                    if cj1 != c_first:
                        insert_cost = d(cj, c_first) + d(c_last, cj1) - d(cj, cj1)
                        if remove_gain - insert_cost > 0:
                            seg_indices = set((i + k) % n for k in range(seg_len))
                            temp = [tour[k] for k in range(n) if k not in seg_indices]
                            ins_pos = None
