                                if c == cj:
                                    ins_pos = k + 1
                                    break
                            if ins_pos is not None:
                                new_tour = temp[:ins_pos] + seg + temp[ins_pos:]
                                if len(new_tour) == n:
                                    for k in range(n):
                                        tour[k] = new_tour[k]
                                        pos[new_tour[k]] = k
                                    improved = True
                                    break

                    # Reverse insertion
                    if seg_len > 1 and cj1 != c_last:
                        insert_cost_r = d(cj, c_last) + d(c_first, cj1) - d(cj, cj1)
                        if remove_gain - insert_cost_r > 0:
                            seg_indices = set((i + k) % n for k in range(seg_len))
                            temp = [tour[k] for k in range(n) if k not in seg_indices]
                            ins_pos = None
                            for k, c in enumerate(temp):
                                if c == cj:
                                    ins_pos = k + 1
                                    break
                            if ins_pos is not None:
                                new_tour = temp[:ins_pos] + list(reversed(seg)) + temp[ins_pos:]
                                if len(new_tour) == n:
                                    for k in range(n):
                                        tour[k] = new_tour[k]
                                        pos[new_tour[k]] = k
                                    improved = True
                                    break

    # Main optimization loop
    # Apply Or-opt first (segments 1, 2, 3), then 2-opt, repeat
    prev_len = float('inf')
    for _ in range(5):
